package main

import("context";"encoding/json";"log";"net/http";"os";"github.com/jackc/pgx/v5/pgxpool")
type product struct{ID string `json:"id"`;Name string `json:"name"`;Category string `json:"category"`;Price float64 `json:"price"`;Inventory int `json:"inventory"`}
func reply(w http.ResponseWriter,s int,v any){w.Header().Set("Content-Type","application/json");w.WriteHeader(s);_=json.NewEncoder(w).Encode(v)}
func main(){ctx:=context.Background();db,e:=pgxpool.New(ctx,os.Getenv("DATABASE_URL"));if e!=nil{log.Fatal(e)};defer db.Close();_,e=db.Exec(ctx,`CREATE TABLE IF NOT EXISTS products(id text PRIMARY KEY,name text NOT NULL,category text NOT NULL,price numeric(12,2) NOT NULL CHECK(price>=0),inventory integer NOT NULL CHECK(inventory>=0)); INSERT INTO products VALUES('iphone-15-pro','Apple iPhone 15 Pro','Electronics',829.99,8),('charizard-base','Pokémon Base Set Charizard','Collectibles',310,1),('new-balance-9060','New Balance 9060 Sea Salt','Fashion',114.5,12),('aeron-chair','Herman Miller Aeron Chair','Home & Garden',599,3) ON CONFLICT(id) DO NOTHING`);if e!=nil{log.Fatal(e)};mux:=http.NewServeMux();mux.HandleFunc("GET /health",func(w http.ResponseWriter,r *http.Request){if db.Ping(r.Context())!=nil{reply(w,503,map[string]string{"service":"catalog","status":"unavailable"});return};reply(w,200,map[string]string{"service":"catalog","status":"ok"})});mux.HandleFunc("GET /products",func(w http.ResponseWriter,r *http.Request){q:=`SELECT id,name,category,price::float8,inventory FROM products`;a:=[]any{};if c:=r.URL.Query().Get("category");c!=""{q+=" WHERE category=$1";a=append(a,c)};q+=" ORDER BY name";rows,e:=db.Query(r.Context(),q,a...);if e!=nil{reply(w,500,map[string]string{"error":"catalog_query_failed"});return};defer rows.Close();items:=[]product{};for rows.Next(){var p product;if rows.Scan(&p.ID,&p.Name,&p.Category,&p.Price,&p.Inventory)==nil{items=append(items,p)}};reply(w,200,map[string]any{"items":items})});mux.HandleFunc("GET /products/{id}",func(w http.ResponseWriter,r *http.Request){var p product;e:=db.QueryRow(r.Context(),`SELECT id,name,category,price::float8,inventory FROM products WHERE id=$1`,r.PathValue("id")).Scan(&p.ID,&p.Name,&p.Category,&p.Price,&p.Inventory);if e!=nil{reply(w,404,map[string]string{"error":"product_not_found"});return};reply(w,200,p)});port:=os.Getenv("PORT");if port==""{port="4001"};log.Fatal(http.ListenAndServe(":"+port,mux))}
